const SwipeableMessage = React.memo(
  ({
    item,
    isMe,
    children,
    onReply,
    themeTextSecondary,
  }: {
    item: Message;
    isMe: boolean;
    children: React.ReactNode;
    onReply: (item: Message) => void;
    themeTextSecondary: string;
  }) => {
    const translateX = useRef(new Animated.Value(0)).current;
    const itemRef = useRef(item);
    const onReplyRef = useRef(onReply);
    itemRef.current = item;
    onReplyRef.current = onReply;

    const panResponder = useRef(
      PanResponder.create({
        onMoveShouldSetPanResponder: (_, gestureState) => {
          return (
            Math.abs(gestureState.dx) > 10 &&
            Math.abs(gestureState.dy) < 10 &&
            gestureState.dx < 0
          );
        },
        onPanResponderMove: (_, gestureState) => {
          if (gestureState.dx < 0) {
            translateX.setValue(Math.max(gestureState.dx, -80));
          }
        },
        onPanResponderRelease: (_, gestureState) => {
          if (gestureState.dx < -50) {
            onReplyRef.current(itemRef.current);
            Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
          }
          Animated.spring(translateX, {
            toValue: 0,
            useNativeDriver: true,
          }).start();
        },
      }),
    ).current;

    return (
      <View style={{ overflow: "hidden" }}>
        <View
          style={[
            {
              position: "absolute",
              right: isMe ? undefined : 8,
              left: isMe ? 8 : undefined,
              top: 0,
              bottom: 0,
              justifyContent: "center",
            },
          ]}
        >
          <Feather name="corner-up-left" size={20} color={themeTextSecondary} />
        </View>
        <Animated.View
          style={{ transform: [{ translateX }] }}
          {...panResponder.panHandlers}
        >
          {children}
        </Animated.View>
      </View>
    );
  },
);

const WavyWaveform = ({
  isPlaying,
  progress,
  isMe,
  theme,
}: {
  isPlaying: boolean;
  progress: number;
  isMe: boolean;
  theme: any;
}) => {
  const [animations] = useState(() =>
    Array.from({ length: 20 }).map(() => new Animated.Value(1)),
  );

  useEffect(() => {
    if (isPlaying) {
      const loops = animations.map((anim) => {
        return Animated.loop(
          Animated.sequence([
            Animated.timing(anim, {
              toValue: Math.random() * 1.5 + 0.5,
              duration: 300 + Math.random() * 200,
              useNativeDriver: false,
            }),
            Animated.timing(anim, {
              toValue: 1,
              duration: 300 + Math.random() * 200,
              useNativeDriver: false,
            }),
          ]),
        );
      });
      loops.forEach((l) => l.start());
      return () => loops.forEach((l) => l.stop());
    } else {
      animations.forEach((anim) =>
        Animated.spring(anim, { toValue: 1, useNativeDriver: false }).start(),
      );
    }
  }, [isPlaying]);

  return (
    <View
      style={{
        flexDirection: "row",
        alignItems: "center",
        height: 24,
        gap: 2,
        flex: 1,
        overflow: "hidden",
      }}
    >
      {animations.map((anim, i) => {
        const isActive = i / 20 <= progress;
        return (
          <Animated.View
            key={i}
            style={{
              width: 3,
              height: 12,
              transform: [{ scaleY: anim }],
              backgroundColor: isActive
                ? isMe
                  ? "#FFF"
                  : theme.primary
                : isMe
                  ? "rgba(255,255,255,0.3)"
                  : "rgba(0,0,0,0.2)",
              borderRadius: 2,
            }}
          />
        );
      })}
    </View>
  );
};

