              toValue: 1,
              duration: 300,
              useNativeDriver: true,
            }),
            Animated.timing(anim, {
              toValue: 0,
              duration: 300,
              useNativeDriver: true,
            }),
          ]),
        );
      useFocusEffect(
        useCallback(() => {
          const timer = setTimeout(() => {
            inputRef.current?.focus();
          }, 300);
          return () => clearTimeout(timer);
        }, []),
      );
      const a1 = createDotAnimation(typingDotAnim1, 0);
      const a2 = createDotAnimation(typingDotAnim2, 150);
      const a3 = createDotAnimation(typingDotAnim3, 300);
      a1.start();
      a2.start();
      a3.start();
      return () => {
        a1.stop();
        a2.stop();
        a3.stop();
        typingDotAnim1.setValue(0);
        typingDotAnim2.setValue(0);
        typingDotAnim3.setValue(0);
      };
    }
  }, [isTyping]);

