  const sendMessage = async (
    content?: string,
    type: string = "text",
    extraData?: any,
  ) => {
    const textToSend = content || message.trim();
    if (!textToSend && type === "text") return;
    if (!matchId || !token || sending) return;

    setMessage("");
    setSending(true);
    if (userId) {
      AsyncStorage.removeItem(`chat_draft_${userId}`).catch((e) =>
        console.error("Failed to clear draft", e),
      );
    }
    setShowEmojiPicker(false);
    setShowAISuggestions(false);

    let replyData: any = undefined;
    if (replyingTo) {
      const replySenderId =
        typeof replyingTo.sender === "string"
          ? replyingTo.sender
          : replyingTo.sender?._id;
      replyData = {
        messageId: replyingTo._id,
        content: replyingTo.content || replyingTo.text || "",
        type: replyingTo.type,
        senderName: String(replySenderId) === String(myId) ? "You" : userName,
      };
    }

    const tempMessage: Message = {
      _id: `temp_${Date.now()}`,
      sender: myId,
      content: textToSend,
      type: type as any,
      createdAt: new Date().toISOString(),
      status: "sent",
      ...(replyData ? { replyTo: replyData } : {}),
      ...extraData,
    };
    setMessages((prev) => [...prev, tempMessage]);
    setReplyingTo(null);
    setTimeout(() => flatListRef.current?.scrollToEnd({ animated: true }), 100);

    try {
      const response = await post<{ message: Message }>(
        `/chat/${matchId}/message`,
        {
          content: textToSend,
          type,
          ...(replyData ? { replyTo: replyData } : {}),
          ...extraData,
        },
        token,
      );
      if (response.success && response.data?.message) {
        setMessages((prev) =>
          prev.map((m) =>
            m._id === tempMessage._id ? response.data!.message : m,
          ),
        );
      }
    } catch (error) {
      console.error("Send error:", error);
      setMessages((prev) => prev.filter((m) => m._id !== tempMessage._id));
      Alert.alert("Error", "Failed to send message");
    } finally {
      setSending(false);
    }
  };

