  const startRecording = async () => {
    if (Platform.OS === "web") {
      Alert.alert(
        "Not Supported",
        "Voice recording is only available in the mobile app",
      );
      return;
    }

    if (isRecording || recordingRef.current) return;

    try {
      const permission = await Audio.requestPermissionsAsync();
      if (!permission.granted) {
        Alert.alert("Permission Needed", "Microphone permission is required");
        return;
      }

      if (soundRef.current) {
        try {
          await soundRef.current.stopAsync();
          await soundRef.current.unloadAsync();
        } catch (_) {}
        soundRef.current = null;
        playingAudioIdRef.current = null;
        setPlayingAudioId(null);
        setAudioProgress(0);
      }

      await Audio.setAudioModeAsync({
        allowsRecordingIOS: true,
        playsInSilentModeIOS: true,
      });

      const { recording } = await Audio.Recording.createAsync(
        Audio.RecordingOptionsPresets.HIGH_QUALITY,
      );
      recordingRef.current = recording;
      setIsRecording(true);
      setRecordingDuration(0);
      recordingDurationRef.current = 0;

      if (matchId) {
        socketService.emit("chat:recording-voice", {
          chatId: matchId,
          userId: myId,
          isRecording: true,
        });
      }

      recordingIntervalRef.current = setInterval(() => {
        recordingDurationRef.current += 1;
        setRecordingDuration((prev) => prev + 1);
      }, 1000);

      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    } catch (error) {
      console.error("Recording error:", error);
      recordingRef.current = null;
      await Audio.setAudioModeAsync({
        allowsRecordingIOS: false,
        playsInSilentModeIOS: true,
      }).catch(() => {});
      Alert.alert("Error", "Could not start recording. Please try again.");
    }
  };

  const stopRecording = async () => {
    if (!recordingRef.current) {
      setIsRecording(false);
      return;
    }

    try {
      if (recordingIntervalRef.current) {
        clearInterval(recordingIntervalRef.current);
        recordingIntervalRef.current = null;
      }

      const recording = recordingRef.current;
      const duration = recordingDurationRef.current;
      recordingRef.current = null;
      setIsRecording(false);

      if (matchId) {
        socketService.emit("chat:recording-voice", {
          chatId: matchId,
          userId: myId,
          isRecording: false,
        });
      }

      await recording.stopAndUnloadAsync();
      await Audio.setAudioModeAsync({
        allowsRecordingIOS: false,
        playsInSilentModeIOS: true,
      }).catch(() => {});
      const uri = recording.getURI();

      if (uri && duration >= 1) {
        try {
          const ext = uri.split(".").pop()?.toLowerCase() || "m4a";
          const mimeMap: Record<string, string> = {
            m4a: "audio/m4a",
            mp4: "audio/mp4",
            caf: "audio/x-caf",
            wav: "audio/wav",
            "3gp": "audio/3gpp",
            aac: "audio/aac",
            webm: "audio/webm",
          };
          const mimeType =
            mimeMap[ext] ||
            (Platform.OS === "android"
              ? "application/octet-stream"
              : "audio/m4a");
          const fileName = `voice_message.${ext}`;
          const formData = new FormData();
          formData.append("audio", {
            uri,
            type: mimeType,
            name: fileName,
          } as any);
          formData.append("duration", duration.toString());

          const uploadResponse = await fetch(
            `${getApiBaseUrl()}/api/upload/audio`,
            {
              method: "POST",
              headers: { Authorization: `Bearer ${token}` },
              body: formData,
            },
          );

          const uploadData = await uploadResponse.json();
          if (uploadData.success && uploadData.url) {
            await sendMessage(`🎤 Voice message (${duration}s)`, "audio", {
              audioUrl: uploadData.url,
              audioDuration: duration,
            });
          } else {
            Alert.alert(
              "Upload Failed",
              uploadData.message || "Could not upload voice message",
            );
          }
        } catch (error) {
          console.error("Voice upload error:", error);
          Alert.alert("Error", "Failed to upload voice message");
        }
      } else if (uri && duration < 1) {
        Alert.alert(
          "Too Short",
          "Voice message must be at least 1 second long",
        );
      }

      setRecordingDuration(0);
      recordingDurationRef.current = 0;
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    } catch (error) {
      console.error("Stop recording error:", error);
      setIsRecording(false);
      setRecordingDuration(0);
      recordingDurationRef.current = 0;
      await Audio.setAudioModeAsync({
        allowsRecordingIOS: false,
        playsInSilentModeIOS: true,
      }).catch(() => {});
    }
  };

  const cancelRecording = async () => {
    if (recordingIntervalRef.current) {
      clearInterval(recordingIntervalRef.current);
      recordingIntervalRef.current = null;
    }

    if (!recordingRef.current) {
      setIsRecording(false);
      setRecordingDuration(0);
      recordingDurationRef.current = 0;
      return;
    }

    try {
      if (Platform.OS !== "web") {
        const recording = recordingRef.current;
        recordingRef.current = null;
        await recording.stopAndUnloadAsync();
        await Audio.setAudioModeAsync({
          allowsRecordingIOS: false,
          playsInSilentModeIOS: true,
        }).catch(() => {});
      } else {
        recordingRef.current = null;
      }
    } catch (error) {
      console.log("Cancel recording cleanup:", error);
    }

    if (matchId) {
      socketService.emit("chat:recording-voice", {
        chatId: matchId,
        userId: myId,
        isRecording: false,
      });
    }

    setIsRecording(false);
    setRecordingDuration(0);
    recordingDurationRef.current = 0;
  };

  const updatePlayingId = (id: string | null) => {
    playingAudioIdRef.current = id;
    setPlayingAudioId(id);
