  const playAudio = async (audioUrl: string, messageId: string) => {
    try {
      if (!audioUrl || audioUrl.trim() === "") {
        Alert.alert("Error", "No audio URL available for this voice message");
        return;
      }

      const currentId = playingAudioIdRef.current;

      // HTML5 Audio pause/play toggle
      if (htmlAudioRef.current) {
        if (currentId === messageId && !htmlAudioRef.current.paused) {
          htmlAudioRef.current.pause();
          updatePlayingId("paused:" + messageId);
          return;
        }
        if (
          currentId === "paused:" + messageId &&
          htmlAudioRef.current.paused
        ) {
          htmlAudioRef.current.play();
          updatePlayingId(messageId);
          return;
        }

        // If clicking a different audio, stop the current one
        htmlAudioRef.current.pause();
        htmlAudioRef.current.src = "";
        htmlAudioRef.current = null;
      }

      // Expo AV pause/play toggle
      if (soundRef.current) {
        try {
          const status: any = await soundRef.current.getStatusAsync();
          if (status.isLoaded) {
            if (currentId === messageId && status.isPlaying) {
              await soundRef.current.pauseAsync();
              updatePlayingId("paused:" + messageId);
              return;
            }
            if (currentId === "paused:" + messageId && !status.isPlaying) {
              await soundRef.current.playAsync();
              updatePlayingId(messageId);
              return;
            }
          }
        } catch (e) {
          console.log("Status check error:", e);
        }

        // If clicking a different audio, unload the current one
        try {
          await soundRef.current.stopAsync();
          await soundRef.current.unloadAsync();
        } catch (cleanupErr) {
          console.log("Audio cleanup error:", cleanupErr);
        }
        soundRef.current = null;
      }

      updatePlayingId(null);
      setAudioProgress(0);

      // Start new audio
      if (Platform.OS === "web") {
        try {
          await Audio.setAudioModeAsync({
            allowsRecordingIOS: false,
            playsInSilentModeIOS: true,
            staysActiveInBackground: true,
          });

          const { sound } = await Audio.Sound.createAsync(
            { uri: audioUrl },
            { shouldPlay: true, progressUpdateIntervalMillis: 100 },
            (status: any) => {
              if (status.isLoaded) {
                if (status.durationMillis > 0) {
                  setAudioProgress(
                    status.positionMillis / status.durationMillis,
                  );
                }
                if (status.didJustFinish) {
                  updatePlayingId(null);
                  setAudioProgress(0);
                  if (soundRef.current) {
                    soundRef.current.unloadAsync().catch(() => {});
                    soundRef.current = null;
                  }
                }
              }
            },
          );
          soundRef.current = sound;
          updatePlayingId(messageId);
        } catch (expoError) {
          console.log(
            "expo-av failed on web, trying HTML5 Audio fallback:",
            expoError,
          );
          try {
            const htmlAudio = new window.Audio(audioUrl);
            htmlAudioRef.current = htmlAudio;
            htmlAudio.onended = () => {
              updatePlayingId(null);
              setAudioProgress(0);
            };
            htmlAudio.ontimeupdate = () => {
              if (htmlAudio.duration > 0) {
                setAudioProgress(htmlAudio.currentTime / htmlAudio.duration);
              }
            };
            htmlAudio.onerror = () => {
              updatePlayingId(null);
              setAudioProgress(0);
              Alert.alert(
                "Playback Error",
                "Could not play this voice message. The audio format may not be supported.",
              );
            };
            await htmlAudio.play();
            updatePlayingId(messageId);
          } catch (htmlError: any) {
            console.error("HTML5 Audio fallback also failed:", htmlError);
            Alert.alert(
              "Playback Error",
              `Could not play voice message: ${htmlError.message || "Unknown error"}`,
            );
          }
        }
        return;
      }

      // Mobile
      await Audio.setAudioModeAsync({
        allowsRecordingIOS: false,
        playsInSilentModeIOS: true,
        staysActiveInBackground: true,
      });

      const { sound } = await Audio.Sound.createAsync(
        { uri: audioUrl },
        { shouldPlay: true, progressUpdateIntervalMillis: 100 },
        (status: any) => {
          if (status.isLoaded) {
            if (status.durationMillis > 0) {
              setAudioProgress(status.positionMillis / status.durationMillis);
            }
            if (status.didJustFinish) {
              updatePlayingId(null);
              setAudioProgress(0);
              if (soundRef.current) {
                soundRef.current.unloadAsync().catch(() => {});
                soundRef.current = null;
              }
            }
          }
        },
      );
      soundRef.current = sound;
      updatePlayingId(messageId);
    } catch (error: any) {
      console.error("Audio playback error for URL:", audioUrl, error);
      Alert.alert(
        "Playback Error",
        `Could not play voice message: ${error.message || "Unknown error"}`,
      );
    }
  };

  useEffect(() => {
    return () => {
      if (soundRef.current) {
        soundRef.current.unloadAsync().catch(() => {});
        soundRef.current = null;
      }
      if (htmlAudioRef.current) {
