                        const z = 15;
                        const n = Math.pow(2, z);
                        const fx = ((lng + 180) / 360) * n;
                        const fy =
                          ((1 -
                            Math.log(
                              Math.tan((lat * Math.PI) / 180) +
                                1 / Math.cos((lat * Math.PI) / 180),
                            ) /
                              Math.PI) /
                            2) *
                          n;
                        const cx = Math.floor(fx);
                        const cy = Math.floor(fy);
                        const subTileX = (fx - cx) * 256;
                        const subTileY = (fy - cy) * 256;
                        const MAP_W = 240;
                        const MAP_H = 160;
                        const gridLeft = -(256 + subTileX - MAP_W / 2);
                        const gridTop = -(256 + subTileY - MAP_H / 2);
                        const tiles = [];
                        for (let dy = -1; dy <= 1; dy++) {
                          for (let dx = -1; dx <= 1; dx++) {
                            tiles.push({ x: cx + dx, y: cy + dy, dx, dy });
                          }
                        }
                        return (
                          <Pressable
                            onPress={() => {
                              const label = item.address || `${lat}, ${lng}`;
                              const url = Platform.select({
                                ios: `maps:0,0?q=${label}@${lat},${lng}`,
                                android: `geo:${lat},${lng}?q=${lat},${lng}(${label})`,
                                default: `https://www.google.com/maps/search/?api=1&query=${lat},${lng}`,
                              });
                              Linking.openURL(url!).catch(() => {
                                Linking.openURL(
                                  `https://www.google.com/maps/search/?api=1&query=${lat},${lng}`,
                                );
                              });
                            }}
                            style={styles.locationBubble}
                          >
                            <View style={styles.locationMapContainer}>
                              <View
                                style={[
                                  styles.locationTileGrid,
                                  { top: gridTop, left: gridLeft },
                                ]}
                              >
                                {tiles.map((t, i) => (
                                  <Image
                                    key={i}
                                    source={{
                                      uri:
                                        Platform.OS === "web"
                                          ? `https://basemaps.cartocdn.com/rastertiles/voyager/${z}/${t.x}/${t.y}@2x.png`
                                          : `https://tile.openstreetmap.org/${z}/${t.x}/${t.y}.png`,
                                      headers:
                                        Platform.OS !== "web"
                                          ? { "User-Agent": "AfroConnect/1.0" }
                                          : undefined,
                                    }}
                                    style={styles.locationTile}
                                    contentFit="cover"
                                  />
                                ))}
                              </View>
                              <View style={styles.locationGradientOverlay}>
                                <View style={styles.locationGradientLayer1} />
                                <View style={styles.locationGradientLayer2} />
                                <View style={styles.locationGradientLayer3} />
                              </View>
                              <View style={styles.locationPinOverlay}>
                                <View style={styles.locationPinShadow} />
                                <Ionicons
                                  name="location-sharp"
                                  size={32}
                                  color="#E53935"
                                  style={{
                                    marginTop: -16,
                                    textShadowColor: "rgba(0,0,0,0.3)",
                                    textShadowOffset: { width: 0, height: 2 },
                                    textShadowRadius: 4,
                                  }}
                                />
                              </View>
                            </View>
                            <View
                              style={[
                                styles.locationInfoRow,
                                {
                                  backgroundColor: isMe
                                    ? "rgba(255,255,255,0.12)"
                                    : "rgba(0,0,0,0.03)",
                                },
                              ]}
                            >
                              <View
                                style={[
                                  styles.locationIconCircle,
                                  {
                                    backgroundColor: isMe
                                      ? "rgba(255,255,255,0.2)"
                                      : theme.primary + "18",
                                  },
                                ]}
                              >
                                <Ionicons
                                  name="navigate"
                                  size={14}
                                  color={isMe ? "#FFF" : theme.primary}
                                />
                              </View>
                              <View style={{ flex: 1 }}>
                                <ThemedText
                                  style={[
                                    styles.locationAddress,
                                    { color: isMe ? "#FFF" : theme.text },
                                  ]}
                                  numberOfLines={2}
                                >
