            >
              <Feather
                name={isDark ? "sun" : "moon"}
                size={22}
                color={theme.text}
              />
              <ThemedText style={[styles.optionText, { color: theme.text }]}>
                {isDark ? "Light Mode" : "Dark Mode"}
              </ThemedText>
            </Pressable>

            <Pressable
              style={styles.optionItem}
              onPress={() => {
                setShowOptionsMenu(false);
                setShowReportModal(true);
              }}
            >
              <Feather name="flag" size={22} color="#FF9800" />
              <ThemedText style={[styles.optionText, { color: theme.text }]}>
                Report User
              </ThemedText>
            </Pressable>

            <Pressable style={styles.optionItem} onPress={handleBlockUser}>
              <Feather name="slash" size={22} color="#F44336" />
              <ThemedText style={[styles.optionText, { color: "#F44336" }]}>
                Block User
              </ThemedText>
            </Pressable>

            <Pressable
              style={[
                styles.cancelButton,
                { borderColor: theme.textSecondary, marginTop: 16 },
              ]}
              onPress={() => setShowOptionsMenu(false)}
            >
              <ThemedText
                style={[styles.cancelButtonText, { color: theme.text }]}
              >
                Cancel
              </ThemedText>
            </Pressable>
          </View>
        </Pressable>
      </Modal>

      <Modal
        visible={showThemeModal}
        transparent
        animationType="slide"
        onRequestClose={() => setShowThemeModal(false)}
      >
        <View style={styles.modalOverlay}>
          <View
            style={[styles.themeModal, { backgroundColor: theme.background }]}
          >
            <View style={styles.themeHeader}>
              <ThemedText style={[styles.themeTitle, { color: theme.text }]}>
                Chat Theme
              </ThemedText>
              <Pressable onPress={() => setShowThemeModal(false)}>
                <Feather name="x" size={24} color={theme.text} />
              </Pressable>
            </View>

            <ScrollView contentContainerStyle={styles.themeGrid}>
              {CHAT_THEMES.map((themeItem) => (
                <Pressable
                  key={themeItem.id}
                  style={[
                    styles.themeItem,
                    chatTheme === themeItem.id && {
                      borderColor: theme.primary,
                      borderWidth: 3,
                    },
                  ]}
                  onPress={() => saveChatTheme(themeItem.id)}
                >
                  {themeItem.image ? (
                    <Image
                      source={themeItem.image}
                      style={styles.themePreview}
                      contentFit="cover"
                    />
                  ) : (
                    <View
                      style={[
                        styles.themePreview,
                        { backgroundColor: isDark ? "#1A1A1A" : "#E8E8E8" },
                      ]}
                    >
                      <ThemedText style={{ color: theme.textSecondary }}>
                        Default
                      </ThemedText>
                    </View>
                  )}
                  <ThemedText
                    style={[styles.themeName, { color: theme.text }]}
                    numberOfLines={1}
                  >
                    {themeItem.name}
                  </ThemedText>
                  {chatTheme === themeItem.id && (
                    <View
                      style={[
                        styles.themeCheck,
                        { backgroundColor: theme.primary },
                      ]}
                    >
                      <Feather name="check" size={12} color="#FFF" />
                    </View>
                  )}
                </Pressable>
              ))}
            </ScrollView>
          </View>
        </View>
      </Modal>

      <Modal
        visible={showReportModal}
        transparent
        animationType="slide"
        onRequestClose={() => setShowReportModal(false)}
      >
        <View style={styles.modalOverlay}>
          <View
            style={[styles.reportModal, { backgroundColor: theme.background }]}
          >
            <View style={styles.reportHeader}>
              <ThemedText style={[styles.reportTitle, { color: theme.text }]}>
                Report {userName}
              </ThemedText>
              <Pressable onPress={() => setShowReportModal(false)}>
                <Feather name="x" size={24} color={theme.text} />
              </Pressable>
            </View>

            <ThemedText
              style={[styles.reportSubtitle, { color: theme.textSecondary }]}
            >
              Why are you reporting this user?
            </ThemedText>

            <ScrollView style={styles.reportReasons}>
              {REPORT_REASONS.map((reason) => (
                <Pressable
                  key={reason.id}
                  style={[
                    styles.reportReasonItem,
                    selectedReportReason === reason.id && {
                      backgroundColor: theme.primary + "20",
                      borderColor: theme.primary,
                    },
                    {
                      borderColor: isDark
                        ? "rgba(255,255,255,0.1)"
                        : "rgba(0,0,0,0.1)",
                    },
                  ]}
                  onPress={() => setSelectedReportReason(reason.id)}
                >
                  <Feather
                    name={reason.icon as any}
                    size={20}
                    color={
                      selectedReportReason === reason.id
                        ? theme.primary
                        : theme.text
                    }
                  />
                  <ThemedText
                    style={[styles.reportReasonText, { color: theme.text }]}
                  >
                    {reason.label}
                  </ThemedText>
                  {selectedReportReason === reason.id && (
                    <Feather
                      name="check-circle"
                      size={20}
                      color={theme.primary}
                    />
                  )}
                </Pressable>
              ))}
            </ScrollView>

            <TextInput
              style={[
                styles.reportInput,
                {
                  color: theme.text,
                  backgroundColor: isDark ? "#2A2A2A" : "#F5F5F5",
                  borderColor: isDark
                    ? "rgba(255,255,255,0.1)"
                    : "rgba(0,0,0,0.1)",
                },
              ]}
              placeholder="Add more details (optional)"
              placeholderTextColor={theme.textSecondary}
              value={reportDetails}
              onChangeText={setReportDetails}
              multiline
              numberOfLines={3}
            />

            <Pressable
              style={[
                styles.submitReportButton,
                {
                  backgroundColor: theme.primary,
                  opacity: selectedReportReason ? 1 : 0.5,
                },
              ]}
              onPress={handleSubmitReport}
              disabled={!selectedReportReason || submittingReport}
            >
              {submittingReport ? (
                <ActivityIndicator color="#FFF" />
              ) : (
                <ThemedText style={styles.submitReportText}>
                  Submit Report
                </ThemedText>
              )}
            </Pressable>
          </View>
        </View>
      </Modal>

      <Modal
        visible={!!viewingImage}
        transparent
        animationType="fade"
        onRequestClose={() => setViewingImage(null)}
      >
        <View style={styles.imageViewerOverlay}>
          <Pressable
            style={styles.imageViewerClose}
            onPress={() => setViewingImage(null)}
          >
            <Feather name="x" size={28} color="#FFF" />
          </Pressable>
          <View style={styles.imageViewerActions}>
            <Pressable
              style={styles.imageViewerActionBtn}
              onPress={() => viewingImage && saveImage(viewingImage)}
            >
              <Ionicons name="download-outline" size={24} color="#FFF" />
            </Pressable>
          </View>
          {viewingImage && (
            <Image
              source={{ uri: viewingImage }}
              style={styles.imageViewerImage}
              contentFit="contain"
            />
          )}
        </View>
      </Modal>

      <Modal
        visible={!!viewingVideo}
        transparent
        animationType="fade"
        onRequestClose={() => setViewingVideo(null)}
      >
        <View style={styles.imageViewerOverlay}>
          <Pressable
            style={styles.imageViewerClose}
            onPress={() => setViewingVideo(null)}
          >
            <Feather name="x" size={28} color="#FFF" />
          </Pressable>
          <View style={styles.imageViewerActions}>
            <Pressable
              style={styles.imageViewerActionBtn}
              onPress={() => viewingVideo && saveVideo(viewingVideo)}
            >
              <Ionicons name="download-outline" size={24} color="#FFF" />
            </Pressable>
          </View>
          {viewingVideo && (
            <Video
              source={{ uri: viewingVideo }}
              style={{ width: "100%", height: "80%" }}
              useNativeControls
              resizeMode={ResizeMode.CONTAIN}
              shouldPlay
              isLooping={false}
            />
          )}
        </View>
      </Modal>

      <Modal
        visible={showMessageMenu}
        transparent
        animationType="fade"
        onRequestClose={() => {
          setShowMessageMenu(false);
          setSelectedMessage(null);
        }}
      >
        <Pressable
          style={styles.modalOverlay}
          onPress={() => {
            setShowMessageMenu(false);
            setSelectedMessage(null);
          }}
        >
          <View
            style={[
              styles.messageMenuModal,
              { backgroundColor: theme.background },
            ]}
          >
            {selectedMessage && (
              <View
                style={[
                  styles.messageMenuPreview,
                  { backgroundColor: isDark ? "#2A2A2A" : "#F5F5F5" },
                ]}
              >
                <ThemedText
                  style={[styles.messageMenuPreviewText, { color: theme.text }]}
                  numberOfLines={2}
                >
                  {selectedMessage.content ||
                    selectedMessage.text ||
                    (selectedMessage.type === "image"
                      ? "📷 Photo"
                      : selectedMessage.type === "video"
                        ? "🎬 Video"
                        : "🎤 Voice")}
                </ThemedText>
              </View>
            )}

            <Pressable style={styles.messageMenuItem} onPress={handleReply}>
              <Feather name="corner-up-left" size={22} color={theme.primary} />
              <ThemedText
                style={[styles.messageMenuItemText, { color: theme.text }]}
              >
                Reply
              </ThemedText>
            </Pressable>

            <Pressable
              style={styles.messageMenuItem}
              onPress={handleTranslateOpen}
