              <MaterialCommunityIcons
                name="translate"
                size={22}
                color={theme.primary}
              />
              <ThemedText
                style={[styles.messageMenuItemText, { color: theme.text }]}
              >
                Translate
              </ThemedText>
            </Pressable>

            <Pressable
              style={styles.messageMenuItem}
              onPress={handleDeleteForMe}
            >
              <Feather name="trash-2" size={22} color="#FF9800" />
              <ThemedText
                style={[styles.messageMenuItemText, { color: theme.text }]}
              >
                Delete for Me
              </ThemedText>
            </Pressable>

            {selectedMessage &&
              (() => {
                const sid =
                  typeof selectedMessage.sender === "string"
                    ? selectedMessage.sender
                    : selectedMessage.sender?._id;
                return String(sid) === String(myId);
              })() && (
                <Pressable
                  style={styles.messageMenuItem}
                  onPress={handleDeleteForEveryone}
                >
                  <Feather name="trash" size={22} color="#F44336" />
                  <ThemedText
                    style={[styles.messageMenuItemText, { color: "#F44336" }]}
                  >
                    Delete for Everyone
                  </ThemedText>
