              <ThemedText
                style={[styles.cancelButtonText, { color: theme.text }]}
              >
                Cancel
              </ThemedText>
            </Pressable>
          </View>
        </Pressable>
      </Modal>

      <Modal
        visible={showTranslateModal}
        transparent
        animationType="slide"
        onRequestClose={() => {
          setShowTranslateModal(false);
          setSelectedMessage(null);
        }}
