              </View>
            )}

            {translating ? (
              <View style={styles.translateLoading}>
                <ActivityIndicator size="large" color={theme.primary} />
                <ThemedText
                  style={[
                    styles.translateLoadingText,
                    { color: theme.textSecondary },
                  ]}
                >
                  Translating...
                </ThemedText>
              </View>
            ) : translatedText ? (
              <View
                style={[
                  styles.translateResult,
                  {
                    backgroundColor: theme.primary + "15",
                    borderColor: theme.primary,
                  },
                ]}
              >
                <ThemedText
                  style={[
                    styles.translateResultLabel,
                    { color: theme.primary },
                  ]}
                >
                  Translation
                </ThemedText>
                <ThemedText
                  style={[styles.translateResultText, { color: theme.text }]}
                >
                  {translatedText}
                </ThemedText>
                <Pressable
                  style={[
                    styles.translateCopyBtn,
                    { backgroundColor: theme.primary },
                  ]}
                  onPress={handleCopyTranslation}
                >
                  <Feather name="copy" size={16} color="#FFF" />
                  <ThemedText style={styles.translateCopyText}>Copy</ThemedText>
                </Pressable>
              </View>
            ) : (
              <View>
                <ThemedText
                  style={[
                    styles.translatePickLabel,
                    { color: theme.textSecondary },
                  ]}
                >
                  Enter target language
                </ThemedText>
                <TextInput
                  style={[
                    styles.translateLangInput,
                    {
                      color: theme.text,
                      backgroundColor: isDark ? "#2A2A2A" : "#F5F5F5",
                      borderColor: isDark
                        ? "rgba(255,255,255,0.1)"
                        : "rgba(0,0,0,0.1)",
                    },
                  ]}
                  placeholder="Type any language (e.g., Swahili, Korean, Tagalog...)"
                  placeholderTextColor={theme.textSecondary}
                  value={translateTargetLang}
                  onChangeText={setTranslateTargetLang}
                  autoFocus
                />
                <Pressable
                  style={[
                    styles.translateButton,
                    {
                      backgroundColor: theme.primary,
                      opacity: translateTargetLang.trim() ? 1 : 0.5,
                    },
                  ]}
                  onPress={() =>
                    translateTargetLang.trim() &&
                    handleTranslate(translateTargetLang.trim())
                  }
                  disabled={!translateTargetLang.trim()}
                >
                  <MaterialCommunityIcons
                    name="translate"
                    size={20}
                    color="#FFF"
                  />
                  <ThemedText style={styles.translateButtonText}>
                    Translate
                  </ThemedText>
                </Pressable>
              </View>
            )}
          </View>
        </View>
      </Modal>
    </ThemedView>
  );
}

